            ->setFirstResult(($page - 1) * $limit)
            ->setMaxResults($limit)
            ->getQuery()
            ->getResult()
        ;

        return [
            'data' => array_map($definition['normalizer'], $items),
            'meta' => [
                'page' => $page,
                'limit' => $limit,
                'total' => $total,
                'resourceLabel' => $definition['label'],
                'aiReady' => true,
                'gateway' => 'Olinda360 MCP',
            ],
        ];
