        }

        return $definitions[$resource];
    }

    /**
     * Builds the query builder used by MCP resource listings.
     *
     * @param array<string, mixed> $query
     */
    private function createResourceQueryBuilder(string $resource, array $query): QueryBuilder
    {
        $definition = $this->getResourceDefinition($resource);
        $queryBuilder = $this->entityManager->getRepository($definition['entity'])->createQueryBuilder('item');
        $metadata = $this->entityManager->getClassMetadata($definition['entity']);

        if ($metadata->hasField('active')) {
            $queryBuilder
                ->andWhere('item.active = :active')
                ->setParameter('active', true)
            ;
        }

        foreach ($definition['filters'] as $parameter => $field) {
            $value = trim((string) ($query[$parameter] ?? ''));

            if ('' === $value || !$metadata->hasField($field)) {
                continue;
            }

            $queryBuilder
                ->andWhere(sprintf('item.%s = :%s', $field, $parameter))
                ->setParameter($parameter, $value)
            ;
        }

        $search = trim((string) ($query['search'] ?? $query['query'] ?? ''));
        if ('' !== $search) {
            $expression = $queryBuilder->expr()->orX();

            foreach ($definition['search_fields'] as $index => $field) {
                if (!$metadata->hasField($field)) {
                    continue;
                }

                $parameter = sprintf('search_%d', $index);
                $expression->add(sprintf('LOWER(item.%s) LIKE :%s', $field, $parameter));
                $queryBuilder->setParameter($parameter, '%'.mb_strtolower($search).'%');
            }

            if ([] !== $expression->getParts()) {
                $queryBuilder->andWhere($expression);
            }
        }

        foreach ($definition['order_by'] as $field => $direction) {
            if ($metadata->hasField($field)) {
                $queryBuilder->addOrderBy(sprintf('item.%s', $field), $direction);
            }
        }

        return $queryBuilder;
    }

    /**
