        return array_map($definition['normalizer'], $items);
    }

    /**
     * Executes a cross-resource tourism search for AI assistants.
     *
     * @param array<string, mixed> $input
     *
     * @return array{data: list<array<string, mixed>>, meta: array<string, mixed>}
     */
    private function searchTourismTool(array $input): array
    {
        $query = trim((string) ($input['query'] ?? $input['search'] ?? ''));
        $limit = min(12, max(1, (int) ($input['limit'] ?? 6)));
        $perResourceLimit = max(1, (int) ceil($limit / 3));

        $spots = array_map(
            static fn (array $item): array => $item + ['resource' => 'tourist-spots'],
            $this->fetchResourceItems('tourist-spots', ['query' => $query, 'district' => $input['district'] ?? null], $perResourceLimit),
        );
        $accommodations = array_map(
            static fn (array $item): array => $item + ['resource' => 'accommodations'],
            $this->fetchResourceItems('accommodations', ['query' => $query, 'district' => $input['district'] ?? null], $perResourceLimit),
        );
        $guides = array_map(
            static fn (array $item): array => $item + ['resource' => 'guides'],
            $this->fetchResourceItems('guides', ['query' => $query], $perResourceLimit),
        );

        $data = array_slice(array_merge($spots, $accommodations, $guides), 0, $limit);

        return [
            'data' => $data,
            'meta' => [
                'query' => $query,
                'limit' => $limit,
                'sources' => ['tourist-spots', 'accommodations', 'guides'],
                'purpose' => 'tourism-discovery',
            ],
        ];
    }

