    /**
     * Recommends a lightweight itinerary using available tourism resources.
     *
     * @param array<string, mixed> $input
     *
     * @return array{data: list<array<string, mixed>>, meta: array<string, mixed>}
     */
    private function recommendItineraryTool(array $input): array
    {
        $interests = $this->normalizeList($input['interests'] ?? $input['query'] ?? '');
        $district = trim((string) ($input['district'] ?? ''));
        $search = implode(' ', $interests);
        $spots = $this->fetchResourceItems('tourist-spots', ['query' => $search, 'district' => $district], 3);

        if ([] === $spots) {
            $spots = $this->fetchResourceItems('tourist-spots', ['district' => $district], 3);
        }

        $events = $this->fetchResourceItems('events', ['query' => $search, 'district' => $district], 2);
        $accommodations = $this->fetchResourceItems('accommodations', ['district' => $district], 1);

        $itinerary = [];
        $order = 1;

        foreach ($spots as $spot) {
            $itinerary[] = [
                'order' => $order++,
                'type' => 'tourist-spot',
                'title' => $spot['name'] ?? 'Ponto turistico',
                'summary' => $spot['category'] ?? 'Atrativo turistico',
                'reason' => 'Incluido por aderencia ao perfil e relevancia para a experiencia turistica urbana.',
            ];
        }

        foreach ($events as $event) {
            $itinerary[] = [
                'order' => $order++,
                'type' => 'event',
                'title' => $event['title'] ?? 'Evento',
                'summary' => $event['category'] ?? 'Programacao cultural',
                'reason' => 'Complementa o roteiro com agenda local e dinamismo territorial.',
            ];
        }

        foreach ($accommodations as $accommodation) {
            $itinerary[] = [
                'order' => $order++,
                'type' => 'accommodation',
                'title' => $accommodation['name'] ?? 'Hospedagem',
                'summary' => $accommodation['category'] ?? 'Apoio operacional',
                'reason' => 'Oferece apoio logistico para permanencia e deslocamento no destino.',
            ];
        }

        return [
            'data' => $itinerary,
            'meta' => [
                'profile' => $input['profile'] ?? 'visitante-geral',
                'district' => '' === $district ? null : $district,
                'interests' => $interests,
                'durationHours' => (int) ($input['durationHours'] ?? 6),
                'strategy' => 'heuristic-curated-itinerary',
            ],
        ];
    }

