    /**
     * Normalizes a scalar or list input into a string list.
     *
     * @return list<string>
     */
    private function normalizeList(mixed $value): array
    {
        if (is_array($value)) {
            return array_values(array_filter(array_map(static fn (mixed $item): string => trim((string) $item), $value), static fn (string $item): bool => '' !== $item));
        }

        $stringValue = trim((string) $value);

        if ('' === $stringValue) {
            return [];
        }

        return array_values(array_filter(array_map('trim', explode(',', $stringValue)), static fn (string $item): bool => '' !== $item));
    }

